class ATMController:
    def __init__(self, num_atms):
        self.num_atms = num_atms
        self.atm_locks = [threading.Lock() for _ in range(num_atms)]
        self.transaction_log = []
        self.transaction_lock = threading.Lock()

    def perform_transaction(self, atm_id, amount):
        with self.atm_locks[atm_id]:
            time.sleep(random.uniform(0.1, 1.0))  # Simulating transaction processing
            with self.transaction_lock:
                self.transaction_log.append((atm_id, amount))
            return True

    def handle_concurrent_operation(self):
        with self.transaction_lock:
            if len(self.transaction_log) > 1:
                for i in range(len(self.transaction_log) - 1):
                    for j in range(i + 1, len(self.transaction_log)):
                        if self.transaction_log[i][0] == self.transaction_log[j][0]:
                            print(f"Concurrent operation detected at ATM {self.transaction_log[i][0]}")
                            return False
        return True

    def handle_failed_transaction(self):
        with self.transaction_lock:
            if len(self.transaction_log) > 0 and random.random() < 0.05:
                failed_atm = random.randint(0, self.num_atms - 1)
                print(f"Transaction failed at ATM {failed_atm}")
                self.transaction_log.append((failed_atm, 0))
                return False
        return True

    def handle_dupery(self):
        with self.transaction_lock:
            if len(self.transaction_log) > 1:
                for i in range(len(self.transaction_log) - 1):
                    for j in range(i + 1, len(self.transaction_log)):
                        if self.transaction_log[i][1] == self.transaction_log[j][1]:
                            print(f"Dupery detected for amount {self.transaction_log[i][1]}")
                            return False
        return True

    def run(self):
        while True:
            atm_id = random.randint(0, self.num_atms - 1)
            amount = random.uniform(10.0, 1000.0)
            if self.perform_transaction(atm_id, amount) and self.handle_concurrent_operation() and self.handle_failed_transaction() and self.handle_dupery():
                print(f"Transaction successful at ATM {atm_id} for amount {amount:.2f}")
            else:
                print("Transaction failed")
            time.sleep(random.uniform(0.5, 2.0))

