class ATMController:
    def __init__(self, num_atms):
        self.num_atms = num_atms
        self.atm_lock = [threading.Lock() for _ in range(num_atms)]
        self.transaction_queue = []
        self.transaction_id = 0

    def process_transaction(self, atm_id, amount):
        with self.atm_lock[atm_id]:
            time.sleep(random.uniform(0.5, 2))  # Simulate transaction processing
            print(f"ATM {atm_id} processed transaction for {amount}")

    def add_transaction(self, atm_id, amount):
        self.transaction_queue.append((self.transaction_id, atm_id, amount))
        self.transaction_id += 1
        self.process_transaction(atm_id, amount)

    def monitor_transactions(self):
        while True:
            if self.transaction_queue:
                transaction_id, atm_id, amount = self.transaction_queue.pop(0)
                self.process_transaction(atm_id, amount)
                print(f"Processed transaction {transaction_id} on ATM {atm_id} for {amount}")
            else:
                time.sleep(0.1)

    def start(self):
        self.monitor_thread = threading.Thread(target=self.monitor_transactions)
        self.monitor_thread.start()

        for i in range(self.num_atms):
            self.add_transaction(i, random.uniform(100, 1000))

