class ATMSystem:
    def __init__(self):
        self.accounts = {}
        self.transaction_log = []
        self.lock = threading.Lock()

    def create_account(self, account_number, balance):
        with self.lock:
            if account_number in self.accounts:
                return False
            self.accounts[account_number] = balance
            return True

    def deposit(self, account_number, amount):
        with self.lock:
            if account_number not in self.accounts:
                return False
            self.accounts[account_number] += amount
            self.log_transaction(account_number, amount, "deposit")
            return True

    def withdraw(self, account_number, amount):
        with self.lock:
            if account_number not in self.accounts or self.accounts[account_number] < amount:
                return False
            self.accounts[account_number] -= amount
            self.log_transaction(account_number, amount, "withdrawal")
            return True

    def check_balance(self, account_number):
        with self.lock:
            if account_number not in self.accounts:
                return -1
            return self.accounts[account_number]

    def log_transaction(self, account_number, amount, transaction_type):
        timestamp = datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")
        transaction = {
            "timestamp": timestamp,
            "account_number": account_number,
            "amount": amount,
            "type": transaction_type,
            "hash": self.generate_transaction_hash(timestamp, account_number, amount, transaction_type)
        }
        self.transaction_log.append(transaction)

    def generate_transaction_hash(self, timestamp, account_number, amount, transaction_type):
        hash_input = f"{timestamp}:{account_number}:{amount}:{transaction_type}:{os.urandom(16)}"
        return hashlib.sha256(hash_input.encode()).hexdigest()

    def audit_transactions(self):
        with self.lock:
            for transaction in self.transaction_log:
                expected_hash = self.generate_transaction_hash(
                    transaction["timestamp"],
                    transaction["account_number"],
                    transaction["amount"],
                    transaction["type"]
                )
                if transaction["hash"] != expected_hash:
                    print(f"Potential fraud detected in transaction: {transaction}")

