    def __init__(self, location, cash_limit, transaction_limit):
        self.location = location
        self.cash_limit = cash_limit
        self.transaction_limit = transaction_limit
        self.cash_available = cash_limit
        self.transaction_count = 0
        self.lock = threading.Lock()

    def dispense_cash(self, amount):
        with self.lock:
            if self.cash_available >= amount and self.transaction_count < self.transaction_limit:
                self.cash_available -= amount
                self.transaction_count += 1
                print(f"Dispensed {amount} from ATM at {self.location}.")
                return True
            else:
                print(f"Unable to dispense cash from ATM at {self.location}.")
                return False

    def refill_cash(self, amount):
        with self.lock:
            self.cash_available = min(self.cash_limit, self.cash_available + amount)
            print(f"Refilled {amount} cash at ATM in {self.location}.")

class ATMNetwork:
    def __init__(self, atms):
        self.atms = atms
        self.lock = threading.Lock()

    def process_transaction(self, user, amount):
        with self.lock:
            for atm in self.atms:
                if atm.dispense_cash(amount):
                    print(f"Transaction of {amount} successful for user {user}.")
                    return
            print(f"Unable to process transaction of {amount} for user {user}.")

    def monitor_atms(self):
