import random
import threading
import time

class AtmController:
    def __init__(self, num_bills, denominations):
        self.num_bills = num_bills
        self.denominations = denominations
        self.lock = threading.Lock()
        self.transactions = []

    def dispense_cash(self, amount):
        with self.lock:
            bills = []
            remaining_amount = amount
            for denomination in self.denominations:
                if remaining_amount >= denomination:
                    num_bills = min(remaining_amount // denomination, self.num_bills[denomination])
                    self.num_bills[denomination] -= num_bills
                    remaining_amount -= num_bills * denomination
                    bills.extend([denomination] * num_bills)
            if remaining_amount > 0:
                return None
            self.transactions.append(amount)
            return bills

    def check_security(self):
        with self.lock:
            if len(self.transactions) >= 10:
                if len(set(self.transactions[-10:])) < 5:
                    return False
        return True

def simulate_transaction(atm, amount):
    if random.random() < 0.01:
        time.sleep(random.uniform(0.5, 2))
    bills = atm.dispense_cash(amount)
    if bills is None:
        print(f"Failed to dispense {amount}")
    else:
        print(f"Dispensed {', '.join(map(str, bills))}")
    if not atm.check_security():
        print("Security breach detected!")

