    num_bills = {20: 100, 50: 50, 100: 20}
    denominations = [20, 50, 100]
    atm = AtmController(num_bills, denominations)

    while True:
        amount = random.choice([20, 50, 100])
        threading.Thread(target=simulate_transaction, args=(atm, amount)).start()
        time.sleep(random.uniform(0.1, 0.5))

