import threading
import random
import time

class ATMController:
    def __init__(self, total_cash, max_withdrawals_per_minute):
        self.total_cash = total_cash
        self.max_withdrawals_per_minute = max_withdrawals_per_minute
        self.current_withdrawals = 0
        self.lock = threading.Lock()

    def withdraw(self, amount):
        with self.lock:
            if self.total_cash >= amount:
                if self.current_withdrawals < self.max_withdrawals_per_minute:
                    self.total_cash -= amount
                    self.current_withdrawals += 1
                    time.sleep(random.uniform(0.5, 2))  # Simulating processing time
                    self.current_withdrawals -= 1
                    return True
                else:
                    print("Maximum withdrawals per minute reached. Please try again later.")
                    return False
            else:
                print("Insufficient funds in the ATM.")
                return False

    def refill(self, amount):
        with self.lock:
            self.total_cash += amount

def simulate_atm_usage(atm_controller, num_users, max_withdrawal_amount):
    def user_thread():
        while True:
            amount = random.randint(10, max_withdrawal_amount)
            if atm_controller.withdraw(amount):
                print(f"Withdrawal of ${amount} successful.")
            time.sleep(random.uniform(1, 5))  # Simulating user interaction

    threads = []
    for _ in range(num_users):
        t = threading.Thread(target=user_thread)
        t.start()
        threads.append(t)

    for t in threads:
        t.join()

