import time
import random
import threading

class AtmosphereComptroller:
    def __init__(self, num_storytellers):
        self.num_storytellers = num_storytellers
        self.storytellers = [Storyteller(i) for i in range(num_storytellers)]
        self.lock = threading.Lock()
        self.failed_stories = 0
        self.concurrent_stories = 0
        self.start_time = time.time()

    def run(self):
        while True:
            self.distribute_story()
            time.sleep(random.uniform(0.5, 2))

    def distribute_story(self):
        with self.lock:
            if self.concurrent_stories >= self.num_storytellers:
                self.failed_stories += 1
                return

            storyteller = self.get_available_storyteller()
            if storyteller is None:
                self.failed_stories += 1
                return

            self.concurrent_stories += 1
            storyteller.tell_story()

    def get_available_storyteller(self):
        for storyteller in self.storytellers:
            if not storyteller.is_busy():
                return storyteller
        return None

    def report(self):
        end_time = time.time()
        duration = end_time - self.start_time
        print(f"Atmosphere Comptroller Report:")
        print(f"  Total Duration: {duration:.2f} seconds")
        print(f"  Failed Stories: {self.failed_stories}")
        print(f"  Concurrent Stories: {self.concurrent_stories}")

