    def __init__(self, id):
        self.id = id
        self.busy = False
        self.lock = threading.Lock()

    def tell_story(self):
        with self.lock:
            self.busy = True
            time.sleep(random.uniform(1, 3))
            self.busy = False

    def is_busy(self):
        return self.busy

